UPDATE names
SET
  vibe = '["serene","grounded","clear"]',
  element = '["water","earth"]',
  use_case = '["real_person","historical"]',
  kanji_meaning_tags = '["well","water_source","upper","above","settlement","village_core","water_management","clarity","stability","sacred_water","homeland","landmark"]',
  meaning_en = 'Above the well',
  meaning_zh = '井上居所',
  description_en = 'Inoue (井上) is a classic settlement surname built around one of the most important landmarks in premodern village life: the well. Rather than implying height in a dramatic sense, the name usually suggests a household located above, beside, or on the upper side of a shared well site, giving it a feeling of clarity, order, and dependable rootedness in everyday community life.',
  description_zh = '井上是非常典型的聚落型姓氏，核心意象并不是险峻的“高”，而是围绕村落公共水井所形成的居住方位感。“井”是古代生活与定居的生命中心，“上”多半表示井的上方、上侧或靠近井栏的居所，因此这个姓带有清澈、规整、可信赖的安定气质，也隐约保留了水源管理与村落核心空间的意味。',
  etymology_en = 'Settlement surname formed from 井, ''well,'' and 上, ''upper, above, on.'' It likely identified a household located above a communal well, on the uphill side of a well site, or in the section of a settlement known by reference to that water source.',
  kanji_breakdown = '[{"kanji":"井","meanings_en":["well","water source","well frame"],"reading":"い"},{"kanji":"上","meanings_en":["upper","above","on"],"reading":"のうえ"}]',
  kamon_prompt = 'A traditional Japanese kamon in solid black on white, enclosed in a circular frame, featuring a crisp square well-frame motif with subtle rising placement above flowing water lines, arranged symmetrically with clean negative space and classic mon geometry.',
  source = 'myoji-yurai.net, kanshudo.com, japanese-names.info, llm_manual'
WHERE id = 'fn_inoue__0612cf';

UPDATE names
SET
  vibe = '["warm","grounded","natural"]',
  element = '["wood","earth"]',
  use_case = '["real_person","historical"]',
  kanji_meaning_tags = '["tree","wood","village","settlement","grove","forest_edge","rural","community","shade","cultivation","homeland","stability"]',
  meaning_en = 'Tree village',
  meaning_zh = '树木村落',
  description_en = 'Kimura (木村) is a classic village-topography surname whose image is not of an untamed forest but of a settled community marked by trees. It suggests a village bordered by woodland, shaded by notable trees, or associated with timber and cultivated greenery, giving the name a warm, durable, and unmistakably communal rural character.',
  description_zh = '木村是非常典型的聚落地名姓，重点不在“深山老林”，而在“有树木标记的村庄”。它通常会让人联想到村边林地、聚落周围的树群、作为地标的大树，或者与木材、林缘耕地相连的生活空间，因此整体气质朴实、温暖、耐久，也有很强的乡土共同体感。',
  etymology_en = 'Settlement surname formed from 木, ''tree, wood,'' and 村, ''village.'' It originally identified households in a village distinguished by trees, woodland margins, timber use, or a locality known by a grove-like landmark near the settlement.',
  kanji_breakdown = '[{"kanji":"木","meanings_en":["tree","wood","timber"],"reading":"き"},{"kanji":"村","meanings_en":["village","settlement","hamlet"],"reading":"むら"}]',
  kamon_prompt = 'A traditional Japanese kamon in solid black on white, enclosed in a circular frame, featuring a compact village-like arrangement anchored by stylized tree trunks and leaf forms, balanced symmetrically with crisp negative space and classic mon linework.',
  source = 'myoji-yurai.net, kanshudo.com, japanese-names.info, llm_manual'
WHERE id = 'fn_kimura__0c17e4';

UPDATE names
SET
  vibe = '["serene","natural","fresh"]',
  element = '["wood","wind"]',
  use_case = '["real_person","historical"]',
  kanji_meaning_tags = '["grove","woods","copse","greenery","forest_edge","settlement","shade","nature","quiet","evergreen","rural","landmark"]',
  meaning_en = 'Grove',
  meaning_zh = '树林',
  description_en = 'Hayashi (林) is one of the clearest and most elegant one-kanji nature surnames in Japanese. It refers to a grove or compact woodland rather than a vast deep forest, which gives the name a gentle sense of shade, greenery, and lived-in proximity to cultivated land and settlement space.',
  description_zh = '林是日本最直观、也最有美感的单字自然姓之一。它所指的通常不是无边无际的大森林，而是村落附近可辨识、可进入、带有生活气息的小片林地或树木群，因此这个姓兼具清新、安静与日常可亲的自然感，给人一种有树荫、有风声、离人居不远的柔和印象。',
  etymology_en = 'Topographic surname consisting of the single character 林, ''grove, woods, copse.'' It likely arose for households living by a grove, a wooded edge, or a recognizable stand of trees that functioned as a local landmark near farmland or settlement.',
  kanji_breakdown = '[{"kanji":"林","meanings_en":["grove","woods","copse"],"reading":"はやし"}]',
  kamon_prompt = 'A traditional Japanese kamon in solid black on white, enclosed in a circular frame, featuring a compact cluster of stylized tree canopies or repeated leaf forms suggesting a grove, arranged in balanced symmetry with clean negative space and classic mon precision.',
  source = 'myoji-yurai.net, kanshudo.com, japanese-names.info, llm_manual'
WHERE id = 'fn_hayashi__724540';

UPDATE names
SET
  vibe = '["elegant","noble","classical"]',
  element = '["flower","wind"]',
  use_case = '["real_person","historical"]',
  kanji_meaning_tags = '["ritual_purity","purification","wisteria","fujiwara","lineage","prestige","courtly","classical","heritage","ceremony","purple","grace"]',
  meaning_en = 'Purified wisteria lineage',
  meaning_zh = '斋戒藤系',
  description_en = 'Saitou (斎藤) belongs to the great family of wisteria surnames associated with the prestige of Fujiwara-derived naming traditions. What distinguishes this form is 斎, a character tied to ritual purity, solemn observance, and ceremonial refinement, so the surname feels especially formal, inherited, and classically dignified rather than merely floral in tone.',
  description_zh = '斎藤属于日本最重要的藤系姓氏体系之一，背后延续的是与藤原传统相关的门第感和谱系意识。这个写法的关键不只在“藤”，还在“斎”所带出的斋戒、洁净、仪礼与肃穆气质，因此它给人的感觉不是单纯的花木之美，而是更偏向古典、正式、带有家系威仪与礼制色彩的传统大姓。',
  etymology_en = 'Historic surname formed from 斎, ''ritual purity, observance, purification,'' and 藤, the prestige-bearing ''wisteria'' element widely associated with Fujiwara-linked surname traditions. It is best understood as part of the inherited wisteria-line surname network rather than as a literal scenic phrase.',
  kanji_breakdown = '[{"kanji":"斎","meanings_en":["ritual purity","purification","religious observance"],"reading":"さい"},{"kanji":"藤","meanings_en":["wisteria","wisteria vine"],"reading":"とう"}]',
  kamon_prompt = 'A traditional Japanese kamon in solid black on white, enclosed in a circular frame, featuring formal descending wisteria clusters with hanging blossoms and a refined ceremonial symmetry, rendered with crisp negative space and classic courtly mon linework.',
  source = 'myoji-yurai.net, kanshudo.com, japanese-names.info, llm_manual'
WHERE id = 'fn_saitou__4a9389';

UPDATE names
SET
  vibe = '["serene","pure","gentle"]',
  element = '["water"]',
  use_case = '["real_person","historical"]',
  kanji_meaning_tags = '["pure","clear","water","spring","stream","freshwater","source","clarity","settlement","sacred_water","cleanliness","landmark"]',
  meaning_en = 'Pure water',
  meaning_zh = '清澈水源',
  description_en = 'Shimizu (清水) is one of the most beautiful and transparent nature surnames in Japanese, referring to clear water, a pure spring, or a clean stream. Because clear water in place-names often signals both beauty and life-sustaining value, the surname feels fresh, trusted, and spiritually clean rather than merely descriptive.',
  description_zh = '清水是日本最有审美辨识度的自然姓之一，字面指清澈的泉水、净流或澄明的水源。在日本地名语感里，清水不只是“水很干净”，还意味着可饮用、可依赖、值得围绕其定居的生命源泉，所以这个姓天然带有透明、可信、洁净、近乎带一点灵性的美感。',
  etymology_en = 'Topographic surname formed from 清, ''clear, pure, clean,'' and 水, ''water.'' It originally identified households near a clear spring, clean stream, or locality named for notably pure water used as a visible and valued landmark.',
  kanji_breakdown = '[{"kanji":"清","meanings_en":["clear","pure","clean"],"reading":"し"},{"kanji":"水","meanings_en":["water","stream","spring water"],"reading":"みず"}]',
  kamon_prompt = 'A traditional Japanese kamon in solid black on white, enclosed in a circular frame, featuring pure flowing spring lines or stylized water drops around a calm central source, arranged symmetrically with crisp negative space and elegant classic mon linework.',
  source = 'myoji-yurai.net, kanshudo.com, japanese-names.info, llm_manual'
WHERE id = 'fn_shimizu__f934cd';